import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
    Image as ImageIcon, Video, FileText, Mic, Link as LinkIcon, 
    Youtube, Move, X, Plus, MessageSquare, Sparkles, Send, 
    Maximize2, Trash2, Play, FileType, Loader2, Instagram, Square, Smartphone,
    GripHorizontal, ChevronRight, Bot, Cable, Copy, Download, Check, Subtitles,
    Eye, ZoomIn, ZoomOut, MousePointer2, Palette, MoreHorizontal, Group, Ungroup, BoxSelect
} from 'lucide-react';
import { WhiteboardNode, Connection } from '../types';
import { Chat } from '@google/genai';
import { createWhiteboardChatSession, convertNodesToParts } from '../services/geminiService';

const PREVIEW_LIMIT_CHARS = 150;

// Helper to extract YouTube ID
const getYoutubeId = (url: string) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=|shorts\/)([^#&?\/]*).*/;
    const match = url.match(regExp);
    return (match && match[2]) ? match[2] : null;
};

// Custom TikTok Icon
const TikTokIcon = ({ size = 14, className = "" }: { size?: number, className?: string }) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
        <path d="M9 12a4 4 0 1 0 4 4V4a5 5 0 0 0 5 5" />
    </svg>
);

interface ChatMessage {
    role: 'user' | 'model';
    text: string;
}

interface SelectionBox {
    startX: number;
    startY: number;
    currentX: number;
    currentY: number;
}

export const Whiteboard: React.FC = () => {
    // Canvas State
    const [nodes, setNodes] = useState<WhiteboardNode[]>([]);
    const [connections, setConnections] = useState<Connection[]>([]);
    const [transform, setTransform] = useState({ x: 0, y: 0, scale: 1 });
    const [isPanning, setIsPanning] = useState(false);

    // Interaction State
    const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
    const [selectionBox, setSelectionBox] = useState<SelectionBox | null>(null);
    const [isDraggingNodes, setIsDraggingNodes] = useState(false);

    const [resizingNodeId, setResizingNodeId] = useState<string | null>(null);
    const [lastWorldMousePos, setLastWorldMousePos] = useState({ x: 0, y: 0 });
    const [lastPanMousePos, setLastPanMousePos] = useState({ x: 0, y: 0 });

    // Connection Logic State
    const [connectingFromId, setConnectingFromId] = useState<string | null>(null);
    const [mousePos, setMousePos] = useState({ x: 0, y: 0 }); // Current world mouse pos

    // Context Menu State
    const [contextMenu, setContextMenu] = useState<{ x: number, y: number, nodeId?: string } | null>(null);

    // AI & Chat State
    const [activeAiNodeId, setActiveAiNodeId] = useState<string | null>(null);
    const [chats, setChats] = useState<Record<string, ChatMessage[]>>({});
    const chatSessionsRef = useRef<Record<string, Chat | null>>({});
    const [copiedState, setCopiedState] = useState<number | null>(null);

    const [isRecording, setIsRecording] = useState(false);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const audioChunksRef = useRef<Blob[]>([]);

    const [inputMsg, setInputMsg] = useState('');
    const [isChatLoading, setIsChatLoading] = useState(false);

    const chatEndRef = useRef<HTMLDivElement>(null);
    const canvasRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const isInteracting = isDraggingNodes || !!resizingNodeId || !!connectingFromId || !!selectionBox;

    useEffect(() => {
        if (chatEndRef.current && activeAiNodeId) {
            chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [chats, activeAiNodeId]);

    // --- Helpers ---
    const getWorldMousePos = (e: React.MouseEvent) => {
        if (!canvasRef.current) return { x: 0, y: 0 };
        const rect = canvasRef.current.getBoundingClientRect();
        return {
            x: (e.clientX - rect.left - transform.x) / transform.scale,
            y: (e.clientY - rect.top - transform.y) / transform.scale
        };
    };

    // --- Infinite Canvas Logic (Zoom & Pan) ---

    const handleWheel = (e: React.WheelEvent) => {
        if (e.ctrlKey || e.metaKey) {
            // Zoom
            e.preventDefault();
            const zoomSensitivity = 0.001;
            const delta = -e.deltaY * zoomSensitivity;
            const newScale = Math.min(Math.max(0.1, transform.scale + delta), 5);
            setTransform(prev => ({ ...prev, scale: newScale }));
        } else {
            // Pan
            setTransform(prev => ({ ...prev, x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
        }
    };

    const handleCanvasMouseDown = (e: React.MouseEvent) => {
        // Middle click or Space+Click to pan
        if (e.button === 1 || (e.button === 0 && e.altKey)) {
            e.preventDefault();
            setIsPanning(true);
            setLastPanMousePos({ x: e.clientX, y: e.clientY });
            return;
        }

        // Left Click on Empty Canvas
        if (e.button === 0) {
            // Start Box Selection
            if (!e.shiftKey) {
                setSelectedNodeIds(new Set()); // Clear selection if not shifting
            }
            const worldPos = getWorldMousePos(e);
            setSelectionBox({
                startX: worldPos.x,
                startY: worldPos.y,
                currentX: worldPos.x,
                currentY: worldPos.y
            });
        }

        setContextMenu(null);
    };

    const handleCanvasMouseMove = (e: React.MouseEvent) => {
        const worldPos = getWorldMousePos(e);
        setMousePos(worldPos);

        // Panning
        if (isPanning) {
            const dx = e.clientX - lastPanMousePos.x;
            const dy = e.clientY - lastPanMousePos.y;
            setTransform(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
            setLastPanMousePos({ x: e.clientX, y: e.clientY });
            return;
        }

        // Box Selecting
        if (selectionBox) {
            setSelectionBox(prev => prev ? ({ ...prev, currentX: worldPos.x, currentY: worldPos.y }) : null);
            return;
        }

        // Dragging Nodes
        if (isDraggingNodes) {
            const dx = worldPos.x - lastWorldMousePos.x;
            const dy = worldPos.y - lastWorldMousePos.y;

            setNodes(prev => prev.map(n => {
                if (selectedNodeIds.has(n.id)) {
                    return { ...n, position: { x: n.position.x + dx, y: n.position.y + dy } };
                }
                return n;
            }));

            setLastWorldMousePos(worldPos);
            return;
        }

        // Resizing
        if (resizingNodeId) {
            setNodes(prev => prev.map(n => {
                if (n.id === resizingNodeId) {
                    const newWidth = Math.max(200, worldPos.x - n.position.x);
                    const newHeight = Math.max(150, worldPos.y - n.position.y);
                    return { ...n, width: newWidth, height: newHeight };
                }
                return n;
            }));
        }
    };

    const handleCanvasMouseUp = () => {
        // Finalize Box Selection
        if (selectionBox) {
            const x1 = Math.min(selectionBox.startX, selectionBox.currentX);
            const x2 = Math.max(selectionBox.startX, selectionBox.currentX);
            const y1 = Math.min(selectionBox.startY, selectionBox.currentY);
            const y2 = Math.max(selectionBox.startY, selectionBox.currentY);

            const newSelected = new Set(selectedNodeIds);

            nodes.forEach(node => {
                const nw = node.width || 280;
                const nh = node.height || 200;
                // Check AABB Intersection
                if (
                    node.position.x < x2 && 
                    node.position.x + nw > x1 && 
                    node.position.y < y2 && 
                    node.position.y + nh > y1
                ) {
                    newSelected.add(node.id);
                    // Also select siblings if part of a group
                    if (node.groupId) {
                        nodes.filter(n => n.groupId === node.groupId).forEach(g => newSelected.add(g.id));
                    }
                }
            });

            setSelectedNodeIds(newSelected);
            setSelectionBox(null);
        }

        setIsDraggingNodes(false);
        setResizingNodeId(null);
        setConnectingFromId(null);
        setIsPanning(false);
    };

    // --- Node Management ---

    const addNode = useCallback((node: WhiteboardNode) => {
        const defaultDims = {
            width: node.type === 'text' ? 300 : 
                   node.type === 'ai-partner' ? 280 : 
                   node.type === 'youtube' ? 400 : 320,
            height: node.type === 'text' ? 220 : 
                    node.type === 'ai-partner' ? 180 : 
                    node.type === 'youtube' ? 300 : 300
        };
        const newNode = { ...defaultDims, ...node };
        setNodes(prev => [...prev, newNode]);

        if (node.type === 'ai-partner') {
            setChats(prev => ({
                ...prev,
                [newNode.id]: [{ role: 'model', text: "Hello! I'm your AI Creative Partner. I can see images, watch videos, and even create sticky notes for you. Try asking me to 'Brainstorm ideas for this project' or 'Organize this board'." }]
            }));
            setActiveAiNodeId(newNode.id);
        }
    }, []);

    const removeNode = (id: string) => {
        // Remove specific node, or all selected if 'id' is in selection
        let idsToRemove = [id];
        if (selectedNodeIds.has(id)) {
            idsToRemove = Array.from(selectedNodeIds);
        }

        setNodes(prev => prev.filter(n => !idsToRemove.includes(n.id)));
        setConnections(prev => prev.filter(c => !idsToRemove.includes(c.from) && !idsToRemove.includes(c.to)));

        if (idsToRemove.includes(activeAiNodeId || '')) setActiveAiNodeId(null);
        setSelectedNodeIds(new Set());
        setContextMenu(null);
    };

    const updateNodeColor = (id: string, color: string) => {
        const idsToUpdate = selectedNodeIds.has(id) ? Array.from(selectedNodeIds) : [id];
        setNodes(prev => prev.map(n => idsToUpdate.includes(n.id) ? { ...n, color } : n));
        setContextMenu(null);
    };

    // --- Grouping Logic ---

    const handleGroupNodes = () => {
        if (selectedNodeIds.size < 2) return;
        const newGroupId = Math.random().toString(36).substr(2, 9);
        setNodes(prev => prev.map(n => selectedNodeIds.has(n.id) ? { ...n, groupId: newGroupId } : n));
        setContextMenu(null);
    };

    const handleUngroupNodes = () => {
        if (selectedNodeIds.size === 0) return;
        setNodes(prev => prev.map(n => selectedNodeIds.has(n.id) ? { ...n, groupId: undefined } : n));
        setContextMenu(null);
    };

    // --- Global Paste Handler ---
    useEffect(() => {
        const handlePaste = (e: ClipboardEvent) => {
            const target = e.target as HTMLElement;
            if (target.tagName === 'TEXTAREA' || target.tagName === 'INPUT') return;

            const text = e.clipboardData?.getData('text');
            if (!text) return;

            const isUrl = /^(http|https):\/\/[^ "]+$/.test(text.trim());

            if (isUrl) {
                e.preventDefault();
                // Paste at center of current view
                const rect = canvasRef.current?.getBoundingClientRect();
                const centerX = ((rect?.width || window.innerWidth) / 2 - transform.x) / transform.scale;
                const centerY = ((rect?.height || window.innerHeight) / 2 - transform.y) / transform.scale;

                const url = text.trim();
                let type: WhiteboardNode['type'] = 'link';
                let title = 'Link';

                if (url.includes('youtube.com') || url.includes('youtu.be')) {
                    type = 'youtube';
                    title = 'Youtube Video';
                } else if (url.includes('tiktok.com')) {
                    type = 'link';
                    title = 'TikTok';
                } else if (url.includes('instagram.com')) {
                    type = 'link';
                    title = 'IG Reel';
                }

                addNode({
                    id: Date.now().toString(),
                    type,
                    content: url,
                    position: { x: centerX, y: centerY },
                    title
                });
            }
        };

        window.addEventListener('paste', handlePaste);
        return () => window.removeEventListener('paste', handlePaste);
    }, [addNode, transform]);


    // --- Voice Recording ---
    const toggleRecording = async () => {
        if (isRecording) {
            mediaRecorderRef.current?.stop();
            setIsRecording(false);
            mediaRecorderRef.current?.stream.getTracks().forEach(t => t.stop());
        } else {
            try {
                const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
                const mediaRecorder = new MediaRecorder(stream);
                mediaRecorderRef.current = mediaRecorder;
                audioChunksRef.current = [];

                mediaRecorder.ondataavailable = (e) => {
                    if (e.data.size > 0) audioChunksRef.current.push(e.data);
                };

                mediaRecorder.onstop = () => {
                     const mimeType = mediaRecorder.mimeType || 'audio/webm';
                     const blob = new Blob(audioChunksRef.current, { type: mimeType });
                     const reader = new FileReader();
                     reader.readAsDataURL(blob);
                     reader.onloadend = () => {
                         const base64 = (reader.result as string).split(',')[1];
                         // Place near center view
                         const rect = canvasRef.current?.getBoundingClientRect();
                         const cx = ((rect?.width || 800) / 2 - transform.x) / transform.scale;
                         const cy = ((rect?.height || 600) / 2 - transform.y) / transform.scale;

                         addNode({
                             id: Date.now().toString(),
                             type: 'audio',
                             content: base64,
                             mimeType: mimeType,
                             fileName: `Voice Note ${new Date().toLocaleTimeString()}`,
                             title: 'Voice Memo',
                             position: { x: cx, y: cy }
                         });
                     };
                };

                mediaRecorder.start();
                setIsRecording(true);
            } catch (err) {
                console.error("Mic error", err);
                alert("Could not access microphone.");
            }
        }
    };

    // --- Drag & Drop Files ---
    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = "copy";
    };

    const handleDrop = async (e: React.DragEvent) => {
        e.preventDefault();
        const rect = canvasRef.current?.getBoundingClientRect();
        if (!rect) return;

        // Calculate world coordinates from drop point
        const rawX = e.clientX - rect.left;
        const rawY = e.clientY - rect.top;
        const x = (rawX - transform.x) / transform.scale - 100;
        const y = (rawY - transform.y) / transform.scale - 100;

        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            const files = Array.from(e.dataTransfer.files);
            for (const file of files) {
                await processFile(file as File, x, y);
            }
            return;
        }

        const textData = e.dataTransfer.getData('text/plain');
        if (textData) {
            // ... (Same URL detection logic as paste) ...
             let type: WhiteboardNode['type'] = 'text';
            let title = 'Note';

            if (textData.includes('youtube.com') || textData.includes('youtu.be')) {
                type = 'youtube';
                title = 'Youtube Video';
            } else if (textData.startsWith('http')) {
                type = 'link';
                title = 'Link';
            }

            addNode({
                id: Math.random().toString(36).substr(2, 9),
                type,
                content: textData,
                position: { x, y },
                title
            });
        }
    };

    const processFile = (file: File, x: number, y: number) => {
        return new Promise<void>((resolve) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                const result = e.target?.result as string;
                const base64 = result.split(',')[1];
                let type: WhiteboardNode['type'] = 'text';

                if (file.type.startsWith('image/')) type = 'image';
                else if (file.type.startsWith('video/')) type = 'video';
                else if (file.type.startsWith('audio/')) type = 'audio';
                else if (file.type === 'application/pdf') type = 'pdf';

                addNode({
                    id: Math.random().toString(36).substr(2, 9),
                    type,
                    content: base64,
                    mimeType: file.type,
                    fileName: file.name,
                    title: file.name,
                    position: { x, y: y + (nodes.length * 20) } 
                });
                resolve();
            };
            reader.readAsDataURL(file);
        });
    };

    // --- Node Interaction ---

    const handleMouseDownNode = (e: React.MouseEvent, id: string) => {
        if (e.button === 2) { // Right click
            e.stopPropagation();
            e.preventDefault();
            // If right clicking an unselected node, select it solely
            if (!selectedNodeIds.has(id)) {
                 setSelectedNodeIds(new Set([id]));
            }
            setContextMenu({ x: e.clientX, y: e.clientY, nodeId: id });
            return;
        }

        if (connectingFromId) return; 
        e.stopPropagation();

        const node = nodes.find(n => n.id === id);
        if (node?.type === 'ai-partner') {
            setActiveAiNodeId(id);
        }

        const worldPos = getWorldMousePos(e);
        setLastWorldMousePos(worldPos);

        // Selection Logic
        let newSelection = new Set(selectedNodeIds);

        if (e.shiftKey) {
            // Toggle selection
            if (newSelection.has(id)) {
                newSelection.delete(id);
                // Also deselect group siblings if needed, or leave them? 
                // Usually shift+click deselects just the target, but for groups it should probably deselect all.
                if (node?.groupId) {
                    nodes.filter(n => n.groupId === node.groupId).forEach(g => newSelection.delete(g.id));
                }
            } else {
                newSelection.add(id);
                // Select group siblings
                if (node?.groupId) {
                    nodes.filter(n => n.groupId === node.groupId).forEach(g => newSelection.add(g.id));
                }
            }
        } else {
            // Normal Click
            // If clicking a node that is NOT already selected, clear and select this one (and its group)
            if (!newSelection.has(id)) {
                newSelection = new Set([id]);
                if (node?.groupId) {
                    nodes.filter(n => n.groupId === node.groupId).forEach(g => newSelection.add(g.id));
                }
            }
            // If clicking a node that IS selected, keep selection (to allow dragging group)
        }

        setSelectedNodeIds(newSelection);
        setIsDraggingNodes(true);
        setContextMenu(null);
    };

    const handleMouseDownResize = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        e.preventDefault();
        setResizingNodeId(id);
    };

    const handleMouseDownPort = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        e.preventDefault();
        setConnectingFromId(id);
    };

    const handleMouseUpNode = (e: React.MouseEvent, targetId: string) => {
        if (connectingFromId && connectingFromId !== targetId) {
            const exists = connections.some(c => 
                (c.from === connectingFromId && c.to === targetId) || 
                (c.from === targetId && c.to === connectingFromId)
            );

            if (!exists) {
                setConnections(prev => [...prev, {
                    id: Math.random().toString(36).substr(2, 9),
                    from: connectingFromId,
                    to: targetId
                }]);

                const targetNode = nodes.find(n => n.id === targetId);
                if (targetNode?.type === 'ai-partner') {
                    setActiveAiNodeId(targetId);
                }
            }
        }
        setConnectingFromId(null);
    };

    // --- Chat Logic ---

    const handleCopyToClipboard = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopiedState(index);
        setTimeout(() => setCopiedState(null), 2000);
    };

    const handleSendMessage = async (textOverride?: string) => {
        const textToSend = textOverride || inputMsg;
        if (!activeAiNodeId || !textToSend.trim()) return;

        if (!textOverride) setInputMsg('');

        setChats(prev => ({
            ...prev,
            [activeAiNodeId]: [...(prev[activeAiNodeId] || []), { role: 'user', text: textToSend }]
        }));

        setIsChatLoading(true);

        try {
            const sourceNodeIds = connections.filter(c => c.to === activeAiNodeId).map(c => c.from);
            // If no connections, look at all nodes to provide context
            const contextNodes = sourceNodeIds.length > 0 ? nodes.filter(n => sourceNodeIds.includes(n.id)) : nodes;

            let session = chatSessionsRef.current[activeAiNodeId];
            if (!session) {
                session = createWhiteboardChatSession(contextNodes);
                chatSessionsRef.current[activeAiNodeId] = session;
            }

            const contextParts = convertNodesToParts(contextNodes);
            let messagePayload = contextParts.length > 0 ? [...contextParts, { text: `\n\nUser Query: ${textToSend}` }] : textToSend;

            const response = await session.sendMessage({ message: messagePayload });

            // Handle Tool Calls (create_notes, organize_layout, connect_nodes, delete_nodes)
            const toolCalls = response.functionCalls;
            const functionResponseParts: any[] = [];

            if (toolCalls && toolCalls.length > 0) {
                for (const call of toolCalls) {

                    // 1. Create Notes
                    if (call.name === 'create_notes') {
                         const notesToCreate = (call.args as any).notes as any[];
                         const aiNode = nodes.find(n => n.id === activeAiNodeId);
                         let startX = (aiNode?.position.x || 0) - 350; 
                         let startY = aiNode?.position.y || 0;

                         notesToCreate.forEach((note: any, idx: number) => {
                             const newNodeId = Date.now().toString() + idx;

                             addNode({
                                 id: newNodeId,
                                 type: 'text',
                                 title: note.title || 'AI Note',
                                 content: note.content,
                                 color: note.color || '#fef3c7',
                                 position: { x: startX, y: startY + (idx * 240) }
                             });

                             // Auto connect new note to AI
                             setConnections(prev => [...prev, {
                                 id: Math.random().toString(),
                                 from: newNodeId,
                                 to: activeAiNodeId!
                             }]);
                         });

                         functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Created ${notesToCreate.length} notes successfully.` },
                                id: call.id as string
                            }
                        });
                    }

                    // 2. Organize Layout (Move Nodes)
                    if (call.name === 'organize_layout') {
                        const moves = (call.args as any).moves as any[];
                        setNodes(prev => prev.map(n => {
                            const move = moves.find((m: any) => m.id === n.id);
                            if (move) {
                                return { ...n, position: { x: move.x, y: move.y } };
                            }
                            return n;
                        }));

                        functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Moved ${moves.length} nodes to new positions.` },
                                id: call.id as string
                            }
                        });
                    }

                    // 3. Connect Nodes
                    if (call.name === 'connect_nodes') {
                        const newConnections = (call.args as any).connections as any[];
                        setConnections(prev => {
                            const updated = [...prev];
                            newConnections.forEach((conn: any) => {
                                // Avoid duplicates
                                const exists = updated.some(c => 
                                    (c.from === conn.fromId && c.to === conn.toId) || 
                                    (c.from === conn.toId && c.to === conn.fromId)
                                );
                                if (!exists) {
                                    updated.push({
                                        id: Math.random().toString(36).substr(2, 9),
                                        from: conn.fromId,
                                        to: conn.toId
                                    });
                                }
                            });
                            return updated;
                        });

                        functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Created ${newConnections.length} connections.` },
                                id: call.id as string
                            }
                        });
                    }

                    // 4. Delete Nodes
                    if (call.name === 'delete_nodes') {
                        const idsToDelete = (call.args as any).nodeIds as string[];
                        setNodes(prev => prev.filter(n => !idsToDelete.includes(n.id)));
                        setConnections(prev => prev.filter(c => !idsToDelete.includes(c.from) && !idsToDelete.includes(c.to)));

                        functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Deleted ${idsToDelete.length} nodes.` },
                                id: call.id as string
                            }
                        });
                    }

                    // 5. Group Nodes
                    if (call.name === 'group_nodes') {
                        const idsToGroup = (call.args as any).nodeIds as string[];
                        const newGroupId = Math.random().toString(36).substr(2, 9);
                        setNodes(prev => prev.map(n => idsToGroup.includes(n.id) ? { ...n, groupId: newGroupId } : n));

                        functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Grouped ${idsToGroup.length} nodes.` },
                                id: call.id as string
                            }
                        });
                    }

                    // 6. Ungroup Nodes
                    if (call.name === 'ungroup_nodes') {
                        const idsToUngroup = (call.args as any).nodeIds as string[];
                        setNodes(prev => prev.map(n => idsToUngroup.includes(n.id) ? { ...n, groupId: undefined } : n));

                        functionResponseParts.push({
                            functionResponse: {
                                name: call.name,
                                response: { result: `Ungrouped ${idsToUngroup.length} nodes.` },
                                id: call.id as string
                            }
                        });
                    }
                }

                // Send function response back to model
                if (functionResponseParts.length > 0) {
                    const followUp = await session.sendMessage({ message: functionResponseParts });
                    setChats(prev => ({
                        ...prev,
                        [activeAiNodeId]: [...(prev[activeAiNodeId] || []), { role: 'model', text: followUp.text || "Action completed." }]
                    }));
                }

            } else {
                setChats(prev => ({
                    ...prev,
                    [activeAiNodeId]: [...(prev[activeAiNodeId] || []), { role: 'model', text: response.text || "I couldn't generate a response." }]
                }));
            }

        } catch (error: any) {
            console.error("Chat error:", error);
            setChats(prev => ({
                ...prev,
                [activeAiNodeId]: [...(prev[activeAiNodeId] || []), { role: 'model', text: `⚠️ Error: ${error.message}` }]
            }));
        } finally {
            setIsChatLoading(false);
        }
    };

    // --- Render Helpers ---

    const getNodePortPosition = (id: string, type: 'input' | 'output') => {
        const node = nodes.find(n => n.id === id);
        if (!node) return { x: 0, y: 0 };
        const w = node.width || 280;
        const h = node.height || 200;
        const y = node.position.y + h / 2;
        const x = type === 'input' ? node.position.x : node.position.x + w;
        return { x, y };
    };

    const NodeCornerIcon = ({ type, title }: { type: string, title: string }) => {
        const size = 16;
        switch(type) {
            case 'video': return <div className="bg-blue-100 p-1.5 rounded-full text-blue-600 shadow-sm"><Video size={size} /></div>;
            case 'image': return <div className="bg-purple-100 p-1.5 rounded-full text-purple-600 shadow-sm"><ImageIcon size={size} /></div>;
            case 'audio': return <div className="bg-red-100 p-1.5 rounded-full text-red-600 shadow-sm"><Mic size={size} /></div>;
            case 'ai-partner': return <div className="bg-indigo-100 p-1.5 rounded-full text-indigo-600 shadow-sm"><Bot size={size} /></div>;
            case 'youtube': return <div className="bg-red-100 p-1.5 rounded-full text-red-600 shadow-sm"><Youtube size={size} /></div>;
            default: return <div className="bg-slate-100 p-1.5 rounded-full text-slate-600 shadow-sm"><FileText size={size} /></div>;
        }
    };

    return (
        <div className="flex h-[calc(100vh-64px)] bg-slate-50 overflow-hidden relative">

            {/* Whiteboard Canvas */}
            <div 
                ref={canvasRef}
                className={`flex-1 relative overflow-hidden bg-slate-50 ${isPanning ? 'cursor-grabbing' : 'cursor-default'}`}
                onWheel={handleWheel}
                onMouseDown={handleCanvasMouseDown}
                onMouseMove={handleCanvasMouseMove}
                onMouseUp={handleCanvasMouseUp}
                onMouseLeave={handleCanvasMouseUp}
                onDragOver={handleDragOver}
                onDrop={handleDrop}
            >
                 {/* Infinite Canvas Container */}
                 <div 
                    className="absolute top-0 left-0 w-full h-full origin-top-left will-change-transform"
                    style={{ 
                        transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.scale})`,
                        backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)',
                        backgroundSize: '24px 24px'
                    }}
                 >
                     {/* Connections Layer (SVG) */}
                     <svg className="absolute top-[-5000px] left-[-5000px] w-[10000px] h-[10000px] pointer-events-none z-0 overflow-visible">
                         <defs>
                             <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                                 <polygon points="0 0, 10 3.5, 0 7" fill="#cbd5e1" />
                             </marker>
                         </defs>
                         {connections.map(conn => {
                             const start = getNodePortPosition(conn.from, 'output');
                             const end = getNodePortPosition(conn.to, 'input');
                             // Need to offset by the huge SVG padding
                             const offX = 5000; const offY = 5000;

                             const controlPoint1 = { x: start.x + 50, y: start.y };
                             const controlPoint2 = { x: end.x - 50, y: end.y };

                             return (
                                 <path 
                                    key={conn.id}
                                    d={`M ${start.x + offX} ${start.y + offY} C ${controlPoint1.x + offX} ${controlPoint1.y + offY}, ${controlPoint2.x + offX} ${controlPoint2.y + offY}, ${end.x + offX} ${end.y + offY}`}
                                    stroke="#cbd5e1"
                                    strokeWidth="2"
                                    fill="none"
                                    markerEnd="url(#arrowhead)"
                                 />
                             );
                         })}
                         {connectingFromId && (
                             <line 
                                x1={getNodePortPosition(connectingFromId, 'output').x + 5000} 
                                y1={getNodePortPosition(connectingFromId, 'output').y + 5000}
                                x2={mousePos.x + 5000}
                                y2={mousePos.y + 5000}
                                stroke="#9333ea"
                                strokeWidth="2"
                                strokeDasharray="5,5"
                             />
                         )}
                     </svg>

                     {/* Selection Box Render */}
                     {selectionBox && (
                         <div 
                            className="absolute bg-blue-500/10 border border-blue-500/50 z-50 pointer-events-none"
                            style={{
                                left: Math.min(selectionBox.startX, selectionBox.currentX),
                                top: Math.min(selectionBox.startY, selectionBox.currentY),
                                width: Math.abs(selectionBox.currentX - selectionBox.startX),
                                height: Math.abs(selectionBox.currentY - selectionBox.startY)
                            }}
                         ></div>
                     )}

                     {/* Nodes */}
                     {nodes.map(node => {
                         const isSelected = selectedNodeIds.has(node.id);
                         const isGrouped = !!node.groupId;

                         return (
                         <div 
                            key={node.id}
                            className={`absolute rounded-xl shadow-sm border flex flex-col group transition-all duration-200 
                                ${isSelected ? 'ring-2 ring-blue-500 z-30' : 'z-10'}
                                ${node.type === 'ai-partner' 
                                    ? activeAiNodeId === node.id 
                                        ? 'border-purple-500 ring-2 ring-purple-200 shadow-xl shadow-purple-100' 
                                        : 'border-purple-200 bg-white'
                                    : 'border-slate-200 hover:shadow-xl'
                                }
                            `}
                            style={{ 
                                transform: `translate(${node.position.x}px, ${node.position.y}px)`,
                                width: node.width || 280, 
                                height: node.height || 'auto',
                                backgroundColor: node.color || '#ffffff'
                            }}
                            onMouseDown={(e) => handleMouseDownNode(e, node.id)}
                            onMouseUp={(e) => handleMouseUpNode(e, node.id)}
                         >
                             {/* Group Indicator */}
                             {isGrouped && !isSelected && (
                                 <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-slate-100 text-slate-400 px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-wider border border-slate-200">
                                     Grouped
                                 </div>
                             )}

                             {/* Node Header */}
                             <div className={`p-3 border-b border-black/5 flex items-center justify-between rounded-t-xl select-none bg-black/5`}>
                                <div className="flex items-center gap-2 text-xs font-bold text-slate-700 truncate flex-1 mr-2">
                                    <span className="truncate">{node.title}</span>
                                </div>
                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={(e) => { e.stopPropagation(); removeNode(node.id); }} className="text-slate-500 hover:text-red-500 bg-white/50 rounded p-0.5">
                                        <Trash2 size={12} />
                                    </button>
                                </div>
                             </div>

                             {/* Node Content */}
                             <div className={`flex-1 p-3 overflow-hidden relative rounded-b-xl ${isInteracting ? 'pointer-events-none' : ''}`}>
                                 <div className="absolute top-2 right-2 z-10 pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity">
                                     <NodeCornerIcon type={node.type} title={node.title} />
                                 </div>

                                 <div className="relative z-10 h-full">
                                    {node.type === 'text' && (
                                        <textarea 
                                            className="w-full h-full text-sm text-slate-800 resize-none focus:outline-none bg-transparent leading-relaxed"
                                            defaultValue={node.content}
                                            onChange={(e) => { node.content = e.target.value; }} 
                                            placeholder="Type something..."
                                            onMouseDown={(e) => e.stopPropagation()} 
                                        />
                                    )}
                                    {node.type === 'ai-partner' && (
                                        <div className="h-full flex flex-col items-center justify-center text-center space-y-2 p-4">
                                            <div className="w-12 h-12 bg-purple-100 rounded-full flex items-center justify-center text-purple-600 mb-2">
                                                <Sparkles size={24} />
                                            </div>
                                            <p className="text-xs text-slate-500">I can create notes for you. Try asking me to brainstorm.</p>
                                        </div>
                                    )}
                                    {/* ... (Other media types same as before) ... */}
                                    {['image', 'video', 'youtube', 'audio', 'link', 'pdf'].includes(node.type) && (
                                         <div className="w-full h-full flex items-center justify-center text-xs text-slate-400">
                                            {node.type === 'image' && <img src={`data:${node.mimeType};base64,${node.content}`} className="w-full h-full object-cover rounded" />}
                                            {node.type === 'youtube' && (
                                                <div className="w-full h-full bg-black rounded overflow-hidden">
                                                    <iframe 
                                                        width="100%" height="100%" 
                                                        src={`https://www.youtube.com/embed/${getYoutubeId(node.content)}?origin=${window.location.origin}&rel=0`} 
                                                        title="YouTube" frameBorder="0" allowFullScreen
                                                    ></iframe>
                                                </div>
                                            )}
                                            {node.type === 'link' && <a href={node.content} target="_blank" className="text-blue-600 underline break-all">{node.content}</a>}
                                         </div>
                                    )}
                                 </div>

                                 {/* Resize Handle */}
                                 <div 
                                    className="absolute bottom-1 right-1 w-6 h-6 flex items-center justify-center cursor-nwse-resize text-black/20 hover:text-blue-500 z-20 opacity-0 group-hover:opacity-100"
                                    onMouseDown={(e) => handleMouseDownResize(e, node.id)}
                                 >
                                     <GripHorizontal size={16} className="transform -rotate-45" />
                                 </div>
                             </div>

                            {/* Ports */}
                            <div className="absolute top-1/2 -left-3 -translate-y-1/2 w-6 h-6 flex items-center justify-center z-30" title="Input">
                                <div className="w-3 h-3 rounded-full border-2 bg-white border-slate-300"></div>
                            </div>
                            <div 
                                className="absolute top-1/2 -right-3 -translate-y-1/2 w-6 h-6 flex items-center justify-center cursor-crosshair group/handle z-30"
                                onMouseDown={(e) => handleMouseDownPort(e, node.id)}
                                title="Output"
                            >
                                <div className={`w-3 h-3 rounded-full border-2 transition-all ${connectingFromId === node.id ? 'bg-blue-500 border-white scale-125' : 'bg-white border-slate-300 group-hover/handle:bg-blue-500'}`}></div>
                            </div>
                         </div>
                     )})}
                 </div>
            </div>

            {/* Toolbar (Fixed) */}
            <div className="absolute top-6 left-1/2 -translate-x-1/2 bg-white shadow-xl shadow-slate-200/50 border border-slate-200 rounded-full p-2 flex items-center gap-3 z-50">
                <button onClick={() => setTransform(t => ({...t, scale: t.scale + 0.1}))} className="p-2 hover:bg-slate-100 rounded-full text-slate-600"><ZoomIn size={20} /></button>
                <button onClick={() => setTransform(t => ({...t, scale: Math.max(0.1, t.scale - 0.1)}))} className="p-2 hover:bg-slate-100 rounded-full text-slate-600"><ZoomOut size={20} /></button>
                <div className="w-px h-6 bg-slate-200"></div>
                <button onClick={() => addNode({id: Date.now().toString(), type: 'text', content: 'New Note', position: {x: -transform.x/transform.scale + 200, y: -transform.y/transform.scale + 200}, title: 'Note', color: '#fef3c7'})} className="p-2 hover:bg-slate-100 rounded-full text-slate-600"><FileText size={20} /></button>
                <button onClick={() => addNode({id: Date.now().toString(), type: 'ai-partner', content: '', position: {x: -transform.x/transform.scale + 400, y: -transform.y/transform.scale + 200}, title: 'AI Partner'})} className="p-2 bg-purple-50 text-purple-600 rounded-full"><Bot size={20} /></button>
                 <button onClick={() => {
                        const url = prompt("YouTube URL:");
                        if (url) addNode({id: Date.now().toString(), type: 'youtube', content: url, position: {x: -transform.x/transform.scale + 100, y: -transform.y/transform.scale + 100}, title: 'Video'});
                    }} className="p-2 hover:bg-red-50 text-slate-600 hover:text-red-600 rounded-full"><Youtube size={20} />
                </button>
            </div>

            {/* Selection Toolbar (Shows when nodes selected) */}
            {selectedNodeIds.size > 0 && (
                 <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900 text-white shadow-xl rounded-full px-6 py-3 flex items-center gap-4 z-50 animate-in fade-in slide-in-from-bottom-2">
                     <span className="text-xs font-bold text-slate-400">{selectedNodeIds.size} selected</span>
                     <div className="h-4 w-px bg-slate-700"></div>
                     <button onClick={handleGroupNodes} className="flex items-center gap-2 hover:text-blue-400 transition-colors text-sm font-medium">
                         <Group size={16} /> Group
                     </button>
                     <button onClick={handleUngroupNodes} className="flex items-center gap-2 hover:text-red-400 transition-colors text-sm font-medium">
                         <Ungroup size={16} /> Ungroup
                     </button>
                     <div className="h-4 w-px bg-slate-700"></div>
                     <button onClick={() => removeNode(Array.from(selectedNodeIds)[0])} className="flex items-center gap-2 hover:text-red-400 transition-colors text-sm font-medium">
                         <Trash2 size={16} /> Delete
                     </button>
                 </div>
            )}

            {/* Context Menu */}
            {contextMenu && (
                <div 
                    className="fixed bg-white rounded-lg shadow-xl border border-slate-100 p-2 z-[100] min-w-[160px] animate-in fade-in zoom-in-95 duration-100"
                    style={{ left: contextMenu.x, top: contextMenu.y }}
                >
                    <div className="text-xs font-bold text-slate-400 px-2 py-1 uppercase tracking-wider mb-1">Actions</div>
                    {contextMenu.nodeId && (
                        <>
                        <button onClick={() => updateNodeColor(contextMenu.nodeId!, '#fef3c7')} className="flex items-center gap-2 w-full text-left px-2 py-1.5 text-sm hover:bg-yellow-50 rounded text-slate-700"><div className="w-3 h-3 bg-yellow-100 rounded-full border border-yellow-300"></div> Yellow</button>
                        <button onClick={() => updateNodeColor(contextMenu.nodeId!, '#dbeafe')} className="flex items-center gap-2 w-full text-left px-2 py-1.5 text-sm hover:bg-blue-50 rounded text-slate-700"><div className="w-3 h-3 bg-blue-100 rounded-full border border-blue-300"></div> Blue</button>
                        <button onClick={() => updateNodeColor(contextMenu.nodeId!, '#dcfce7')} className="flex items-center gap-2 w-full text-left px-2 py-1.5 text-sm hover:bg-green-50 rounded text-slate-700"><div className="w-3 h-3 bg-green-100 rounded-full border border-green-300"></div> Green</button>
                        <div className="h-px bg-slate-100 my-1"></div>
                        </>
                    )}
                    {selectedNodeIds.size > 1 && (
                         <button onClick={handleGroupNodes} className="flex items-center gap-2 w-full text-left px-2 py-1.5 text-sm hover:bg-slate-50 text-slate-700 rounded"><Group size={14}/> Group</button>
                    )}
                    {selectedNodeIds.size > 0 && Array.from(selectedNodeIds).some(id => nodes.find(n => n.id === id)?.groupId) && (
                         <button onClick={handleUngroupNodes} className="flex items-center gap-2 w-full text-left px-2 py-1.5 text-sm hover:bg-slate-50 text-slate-700 rounded"><Ungroup size={14}/> Ungroup</button>
                    )}
