const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey });

const SUPPORTED_MIME_TYPES = new Set([
  'image/png', 'image/jpeg', 'image/webp', 'image/heic', 'image/heif',
  'video/mp4', 'video/mpeg', 'video/mov', 'video/avi', 'video/x-flv', 'video/mpg', 'video/webm', 'video/wmv', 'video/3gpp',
  'audio/wav', 'audio/mp3', 'audio/aiff', 'audio/aac', 'audio/ogg', 'audio/flac',
  'application/pdf', 'text/plain', 'text/csv', 'text/html'
]);

const parseGeminiResponse = (text: string): Partial<BusinessIdea> => {
  const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/```\n([\s\S]*?)\n```/);
  let parsedIdea: Partial<BusinessIdea> = {};

  if (jsonMatch && jsonMatch[1]) {
    try {
      parsedIdea = JSON.parse(jsonMatch[1]);
    } catch (e) {
      console.error("JSON Parse Error:", e);
    }
  } else {
     try {
       parsedIdea = JSON.parse(text);
     } catch (e) {
       console.error("Failed to parse Gemini response raw", e);
     }
  }
  return parsedIdea;
};

const hydrateIdea = (parsedIdea: Partial<BusinessIdea>, sources: any[]): BusinessIdea => {
  const randomTrendBase = Math.floor(Math.random() * 100);

  return {
    id: Math.random().toString(36).substr(2, 9),
    date: new Date().toLocaleDateString('en-US', { month: 'numeric', day: 'numeric', year: 'numeric' }),
    title: parsedIdea.title || 'Untitled Idea',
    tags: parsedIdea.tags || ['Analysis', 'AI Generated'],
    description: parsedIdea.description || 'No description provided.',
    priceRange: parsedIdea.priceRange || 'Variable',
    trendKeyword: parsedIdea.trendKeyword || 'Market Trend',
    trendVolume: parsedIdea.trendVolume || '5.5K',
    trendGrowth: parsedIdea.trendGrowth || '+85%',
    relatedKeywords: parsedIdea.relatedKeywords || [parsedIdea.trendKeyword || 'Startup Idea'],
    trendData: parsedIdea.trendData || [
      { date: '2022', value: randomTrendBase }, 
      { date: '2023', value: randomTrendBase + 20 }, 
      { date: '2024', value: randomTrendBase + 50 }, 
      { date: '2025', value: randomTrendBase + 80 }, 
      { date: '2026', value: randomTrendBase + 60 }
    ],
    kpi: parsedIdea.kpi || {
       opportunity: { score: 8, label: 'High' },
       problem: { score: 7, label: 'Moderate' },
       feasibility: { score: 7, label: 'Doable' },
       whyNow: { score: 9, label: 'Now' }
    },
    businessFit: parsedIdea.businessFit || {
        revenuePotential: '$$',
        revenuePotentialDescription: 'Moderate revenue potential with standard subscription models.',
        executionDifficulty: 5,
        executionDifficultyDescription: 'Standard development complexity.',
        goToMarket: 5,
        goToMarketDescription: 'Requires standard social media marketing.',
        founderFitDescription: 'Generalist founder with some industry knowledge.'
    },
    sections: parsedIdea.sections || {
        offer: [],
        whyNow: 'N/A',
        proofAndSignals: 'N/A',
        marketGap: 'N/A',
        executionPlan: 'N/A'
    },
    communitySignals: parsedIdea.communitySignals || {
        reddit: 'N/A',
        facebook: 'N/A',
        youtube: 'N/A',
        other: 'N/A'
    },
    sources: sources
  };
}

export const generateBusinessIdea = async (): Promise<BusinessIdea> => {
  // Using gemini-3-flash-preview for high performance and to avoid 503 timeouts
  const modelId = 'gemini-3-flash-preview';

  const today = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const prompt = `
    Act as a world-class venture capitalist and trend analyst. Today is ${today}.

    1. Search for a specific breakout business trend or rising problem from the last 24 hours.
    2. Synthesize a complete, robust business idea ("The Idea of Tomorrow") that solves this problem.
    3. Conduct a keyword analysis for related search terms.
    4. Provide community validation signals.

    Return the response ONLY as a JSON object inside a markdown code block following this exact schema:
    {
      "title": "startup name",
      "description": "3-4 paragraphs of robust, detailed analysis (make it information-rich)",
      "tags": ["Tag1", "Tag2"],
      "trendKeyword": "Main breakout term",
      "relatedKeywords": ["KW1", "KW2", "KW3", "KW4"],
      "trendVolume": "e.g. 12K",
      "trendGrowth": "e.g. +200%",
      "trendData": [{ "date": "Year", "value": 0-100 }],
      "kpi": {
        "opportunity": { "score": 1-10, "label": "Label" },
        "problem": { "score": 1-10, "label": "Label" },
        "feasibility": { "score": 1-10, "label": "Label" },
        "whyNow": { "score": 1-10, "label": "Label" }
      },
      "businessFit": {
        "revenuePotential": "$$$",
        "revenuePotentialDescription": "1-2 robust sentences",
        "executionDifficulty": 1-10,
        "executionDifficultyDescription": "1-2 robust sentences",
        "goToMarket": 1-10,
        "goToMarketDescription": "1-2 robust sentences",
        "founderFitDescription": "1-2 robust sentences"
      },
      "sections": {
        "offer": [{ "type": "Ladder Step", "title": "Title", "description": "Robust explanation", "price": "Price", "valueProvided": "Value", "goal": "Goal" }],
        "whyNow": "3-4 detailed sentences",
        "proofAndSignals": "3-4 detailed sentences",
        "marketGap": "3-4 detailed sentences",
        "executionPlan": "3-4 detailed sentences"
      },
      "communitySignals": { "reddit": "Detailed", "facebook": "Detailed", "youtube": "Detailed", "other": "Detailed" }
    }

    **IMPORTANT**: Ensure all text sections are robust and detailed (multi-sentence). Avoid short placeholders.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    const parsedIdea = parseGeminiResponse(response.text || '');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(c => c.web?.uri && c.web?.title)
      .map(c => ({ title: c.web!.title!, uri: c.web!.uri! })) || [];

    return hydrateIdea(parsedIdea, sources);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const analyzeUserIdea = async (userDescription: string, media?: { data: string, mimeType: string }): Promise<BusinessIdea> => {
  const modelId = 'gemini-3-flash-preview';

  const prompt = `
    Act as a VC expert. Analyze the following idea concept: "${userDescription}"
    ${media ? 'Also analyze the provided media for additional context.' : ''}

    1. Search for real-time market data to validate this idea.
    2. Provide a robust, detailed analysis including a 5-step Value Ladder.

    Return as JSON matching the schema of generateBusinessIdea. Ensure all sections are robust and multi-sentence.
  `;

  const parts: Part[] = [{ text: prompt }];
  if (media) {
      parts.unshift({ inlineData: { data: media.data, mimeType: media.mimeType }});
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    const parsedIdea = parseGeminiResponse(response.text || '');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(c => c.web?.uri && c.web?.title)
      .map(c => ({ title: c.web!.title!, uri: c.web!.uri! })) || [];

    return hydrateIdea(parsedIdea, sources);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

