export const generateBusinessIdea = async (): Promise<BusinessIdea> => {
  // Using gemini-3-flash-preview for basic text tasks and summarization.
  const modelId = 'gemini-3-flash-preview';

  const today = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const prompt = `
    Act as a world-class venture capitalist and trend analyst. Today is ${today}.

    1. Search for a specific breakout business trend or rising problem from the last 24 hours.
    2. Synthesize a complete, robust business idea ("The Idea of Tomorrow") that solves this problem.
    3. Conduct a keyword analysis for related search terms.
    4. Provide community validation signals.

    Return the response ONLY as a JSON object inside a markdown code block following this exact schema:
    {
      "title": "startup name",
      "description": "3-4 paragraphs of robust, detailed analysis (make it information-rich)",
      "tags": ["Tag1", "Tag2"],
      "trendKeyword": "Main breakout term",
      "relatedKeywords": ["KW1", "KW2", "KW3", "KW4"],
      "trendVolume": "e.g. 12K",
      "trendGrowth": "e.g. +200%",
      "trendData": [{ "date": "Year", "value": 0-100 }],
      "kpi": {
        "opportunity": { "score": 1-10, "label": "Label" },
        "problem": { "score": 1-10, "label": "Label" },
        "feasibility": { "score": 1-10, "label": "Label" },
        "whyNow": { "score": 1-10, "label": "Label" }
      },
      "businessFit": {
        "revenuePotential": "$$$",
        "revenuePotentialDescription": "1-2 robust sentences",
        "executionDifficulty": 1-10,
        "executionDifficultyDescription": "1-2 robust sentences",
        "goToMarket": 1-10,
        "goToMarketDescription": "1-2 robust sentences",
        "founderFitDescription": "1-2 robust sentences"
      },
      "sections": {
        "offer": [{ "type": "Ladder Step", "title": "Title", "description": "Robust explanation", "price": "Price", "valueProvided": "Value", "goal": "Goal" }],
        "whyNow": "3-4 detailed sentences",
        "proofAndSignals": "3-4 detailed sentences",
        "marketGap": "3-4 detailed sentences",
        "executionPlan": "3-4 detailed sentences"
      },
      "communitySignals": { "reddit": "Detailed", "facebook": "Detailed", "youtube": "Detailed", "other": "Detailed" }
    }

    **IMPORTANT**: Ensure all text sections are robust and detailed (multi-sentence). Avoid short placeholders.
  `;

  try {
    const response = await withRetry(() => ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    }));

    // Fix: Access response.text directly (property, not method).
    const parsedIdea = parseGeminiResponse(response.text || '');
    // Fix: Cast 'c' as any to avoid 'unknown' property access errors.
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((c: any) => c.web?.uri && c.web?.title)
      .map((c: any) => ({ title: c.web!.title!, uri: c.web!.uri! })) || [];

    return hydrateIdea(parsedIdea, sources);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const analyzeUserIdea = async (userDescription: string, media?: { data: string, mimeType: string }): Promise<BusinessIdea> => {
  const modelId = 'gemini-3-flash-preview';

  const prompt = `
    Act as a VC expert. Analyze the following idea concept: "${userDescription}"
    ${media ? 'Also analyze the provided media for additional context.' : ''}

    1. Search for real-time market data to validate this idea.
    2. Provide a robust, detailed analysis including a 5-step Value Ladder.

    Return as JSON matching the schema of generateBusinessIdea. Ensure all sections are robust and multi-sentence.
