export const createWhiteboardChatSession = (nodes: any[]): Chat => {
  const modelId = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are an AI Creative Partner on a digital whiteboard.
    Current context: ${nodes.length} nodes on board.
    Help the user brainstorm, organize, and connect ideas.
  `;

  const tools: FunctionDeclaration[] = [
    {
      name: 'create_notes',
      description: 'Create new sticky notes',
      parameters: {
        type: Type.OBJECT,
        properties: {
          notes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                color: { type: Type.STRING }
              },
              required: ['content']
            }
          }
        },
        required: ['notes']
      }
    },
    {
      name: 'organize_layout',
      description: 'Re-arrange node positions',
      parameters: {
        type: Type.OBJECT,
        properties: {
          moves: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER }
              },
              required: ['id', 'x', 'y']
            }
          }
        },
        required: ['moves']
      }
    },
    {
        name: 'connect_nodes',
        description: 'Connect two nodes with a line',
        parameters: {
            type: Type.OBJECT,
            properties: {
                connections: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            fromId: { type: Type.STRING },
                            toId: { type: Type.STRING }
                        },
                        required: ['fromId', 'toId']
                    }
                }
            },
            required: ['connections']
        }
    },
    {
        name: 'delete_nodes',
        description: 'Delete nodes from the board',
        parameters: {
            type: Type.OBJECT,
            properties: {
                nodeIds: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            },
            required: ['nodeIds']
        }
    },
    {
        name: 'group_nodes',
        description: 'Group multiple nodes together',
        parameters: {
            type: Type.OBJECT,
            properties: {
                nodeIds: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            },
            required: ['nodeIds']
        }
    },
    {
        name: 'ungroup_nodes',
        description: 'Ungroup nodes',
        parameters: {
            type: Type.OBJECT,
            properties: {
                nodeIds: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            },
            required: ['nodeIds']
        }
    }
  ];

  return ai.chats.create({
    model: modelId,
    config: {
      systemInstruction,
      tools: [{ functionDeclarations: tools }]
    }
  });
};
